"""
YouTube Player Backend - Serves search results & video metadata to APK
yt-dlp based, no API key needed
"""

import json
import os
import sys
import threading
import subprocess
from http.server import HTTPServer, BaseHTTPRequestHandler
from urllib.parse import urlparse, parse_qs

import yt_dlp

PORT = 8765
DOWNLOAD_DIR = "/sdcard/YouTubeDownloads"

os.makedirs(DOWNLOAD_DIR, exist_ok=True)

class YTHandler(BaseHTTPRequestHandler):

    def log_message(self, format, *args):
        pass  # Silent

    def _json(self, data, code=200):
        self.send_response(code)
        self.send_header("Content-Type", "application/json")
        self.send_header("Access-Control-Allow-Origin", "*")
        self.end_headers()
        self.wfile.write(json.dumps(data).encode())

    def _text(self, text, code=200):
        self.send_response(code)
        self.send_header("Content-Type", "text/plain")
        self.send_header("Access-Control-Allow-Origin", "*")
        self.end_headers()
        self.wfile.write(text.encode())

    def do_GET(self):
        parsed = urlparse(self.path)
        params = parse_qs(parsed.query)

        if parsed.path == "/search":
            self.handle_search(params)
        elif parsed.path == "/video":
            self.handle_video(params)
        elif parsed.path == "/trending":
            self.handle_trending()
        elif parsed.path == "/downloads":
            self.handle_downloads()
        elif parsed.path == "/local":
            self.handle_local(params)
        elif parsed.path == "/status":
            self._json({"status": "ok", "port": PORT})
        else:
            self._json({"error": "not found"}, 404)

    def do_POST(self):
        parsed = urlparse(self.path)

        if parsed.path == "/download":
            content_length = int(self.headers.get("Content-Length", 0))
            body = self.rfile.read(content_length).decode()
            try:
                data = json.loads(body)
                self.start_download(data.get("url", ""), data.get("title", "video"))
            except:
                self._json({"error": "bad request"}, 400)
        else:
            self._json({"error": "not found"}, 404)

    def handle_search(self, params):
        query = params.get("q", [""])[0]
        if not query:
            self._json({"error": "no query"})
            return

        try:
            ydl_opts = {
                "quiet": True,
                "extract_flat": "in_playlist",
                "skip_download": True,
                "nocheckcertificate": True,
            }

            with yt_dlp.YoutubeDL(ydl_opts) as ydl:
                result = ydl.extract_info(f"ytsearch10:{query}", download=False)

            videos = []
            if result and "entries" in result:
                for entry in result["entries"]:
                    if not entry:
                        continue
                    vid = entry.get("id", "")
                    duration = entry.get("duration", 0)
                    videos.append({
                        "id": vid,
                        "title": entry.get("title", ""),
                        "channel": entry.get("channel", entry.get("uploader", "")),
                        "duration": duration,
                        "duration_str": self.format_duration(duration),
                        "thumbnail": f"https://i.ytimg.com/vi/{vid}/hqdefault.jpg",
                        "url": f"https://www.youtube.com/watch?v={vid}",
                    })

            self._json({"results": videos})
        except Exception as e:
            self._json({"error": str(e), "results": []})

    def handle_video(self, params):
        vid = params.get("id", [""])[0]
        if not vid:
            self._json({"error": "no id"})
            return

        url = f"https://www.youtube.com/watch?v={vid}"

        try:
            ydl_opts = {
                "quiet": True,
                "skip_download": True,
                "nocheckcertificate": True,
                "format": "best",
            }

            with yt_dlp.YoutubeDL(ydl_opts) as ydl:
                info = ydl.extract_info(url, download=False)

            self._json({
                "id": vid,
                "title": info.get("title", ""),
                "channel": info.get("uploader", ""),
                "duration": info.get("duration", 0),
                "thumbnail": info.get("thumbnail", ""),
                "stream_url": info.get("url", ""),
                "description": (info.get("description") or "")[:500],
            })
        except Exception as e:
            self._json({"error": str(e)})

    def handle_trending(self):
        try:
            ydl_opts = {
                "quiet": True,
                "extract_flat": "in_playlist",
                "skip_download": True,
                "nocheckcertificate": True,
            }

            with yt_dlp.YoutubeDL(ydl_opts) as ydl:
                result = ydl.extract_info("https://www.youtube.com/feed/trending", download=False)

            videos = []
            if result and "entries" in result:
                for entry in result["entries"][:15]:
                    if not entry:
                        continue
                    vid = entry.get("id", "")
                    duration = entry.get("duration", 0)
                    videos.append({
                        "id": vid,
                        "title": entry.get("title", ""),
                        "channel": entry.get("channel", ""),
                        "duration": duration,
                        "duration_str": self.format_duration(duration),
                        "thumbnail": f"https://i.ytimg.com/vi/{vid}/hqdefault.jpg",
                        "url": f"https://www.youtube.com/watch?v={vid}",
                    })

            self._json({"results": videos})
        except Exception as e:
            self._json({"error": str(e), "results": []})

    def handle_downloads(self):
        files = []
        if os.path.exists(DOWNLOAD_DIR):
            for f in sorted(os.listdir(DOWNLOAD_DIR)):
                fp = os.path.join(DOWNLOAD_DIR, f)
                if os.path.isfile(fp):
                    files.append({
                        "name": f,
                        "size_mb": round(os.path.getsize(fp) / 1024 / 1024, 1),
                        "path": fp,
                    })
        self._json({"files": files})

    def handle_local(self, params):
        folder = params.get("folder", ["music"])[0]
        paths = {
            "music": "/sdcard/Music",
            "movies": "/sdcard/Movies",
            "downloads": "/sdcard/Download",
        }
        path = paths.get(folder, "/sdcard/Music")

        exts = {
            "music": [".mp3", ".flac", ".m4a", ".wav", ".ogg"],
            "movies": [".mp4", ".mkv", ".webm", ".avi"],
            "downloads": [".mp4", ".mkv", ".webm", ".mp3"],
        }

        allowed = exts.get(folder, [".mp3", ".mp4"])
        files = []

        if os.path.exists(path):
            for f in sorted(os.listdir(path)):
                fp = os.path.join(path, f)
                if os.path.isfile(fp):
                    ext = os.path.splitext(f)[1].lower()
                    if ext in allowed:
                        files.append({
                            "name": f,
                            "size_mb": round(os.path.getsize(fp) / 1024 / 1024, 1),
                            "path": fp,
                        })

        self._json({"files": files})

    def start_download(self, url, title):
        if not url:
            self._json({"error": "no url"}, 400)
            return

        safe = "".join(c for c in title if c.isalnum() or c in " _-").strip()
        if not safe:
            safe = "video"

        output = os.path.join(DOWNLOAD_DIR, safe + ".mp4")

        def _download():
            try:
                subprocess.run([
                    "python3", "-m", "yt_dlp",
                    "-f", "best[height<=720]",
                    "-o", output,
                    "--no-playlist",
                    url
                ], capture_output=True, timeout=600)
            except:
                pass

        threading.Thread(target=_download, daemon=True).start()
        self._json({"status": "downloading", "title": safe})

    @staticmethod
    def format_duration(seconds):
        if not seconds or seconds <= 0:
            return "LIVE"
        h = seconds // 3600
        m = (seconds % 3600) // 60
        s = seconds % 60
        if h > 0:
            return f"{h}:{m:02d}:{s:02d}"
        return f"{m}:{s:02d}"


def main():
    server = HTTPServer(("127.0.0.1", PORT), YTHandler)
    print(f"🔥 YouTube Backend running on http://127.0.0.1:{PORT}")
    print(f"   /search?q=query    - Search YouTube")
    print(f"   /video?id=VIDEO_ID - Get video stream URL")
    print(f"   /trending          - Trending videos")
    print(f"   /downloads         - List downloaded files")
    print(f"   /local?folder=music- List local media")
    print(f"   POST /download     - Download video")
    try:
        server.serve_forever()
    except KeyboardInterrupt:
        print("\n👋 Server stopped")
        server.server_close()


if __name__ == "__main__":
    main()
